x_snc_airop_check_definition.check_script:
(function() {
    try {
        if (!gs.tableExists("awa_queue")) {
            return { status: "needs_validation", actualValue: "Table not found", finding: "awa_queue table not present -- manual verification required. Confirm Advanced Work Assignment is installed and active." };
        }
        var ga = new GlideAggregate("awa_queue");
        ga.addQuery("active", true);
        ga.addAggregate("COUNT");
        ga.query();
        var count = ga.next() ? parseInt(ga.getAggregate("COUNT")) : 0;
        var actualValue = count + " active agent escalation queues";
        if (count >= 1) {
            return { status: "ready", actualValue: actualValue, finding: count + " active escalation queue(s) configured. Now Assist VA can hand off to human agents when AI cannot resolve the conversation." };
        } else {
            return { status: "value_blocker", actualValue: actualValue, finding: "No active agent escalation queues configured in AWA. Now Assist VA users are stranded when AI cannot resolve their request -- live agent escalation paths are required for a complete self-service experience." };
        }
    } catch(e) {
        return { status: "needs_validation", actualValue: "Check failed", finding: "Script execution error: " + e.message };
    }
})
